from odoo import models, fields, api


class HrApplicant(models.Model):
    """Extend hr.applicant: show 'Schedule Interview' when stage name contains 'interview';
    open invite form with candidate/position defaults; and expose job kanban notes."""

    _inherit = 'hr.applicant'

    show_interview_button = fields.Boolean(
        compute='_compute_show_interview_button',
        store=False
    )
    job_kanban_notes = fields.Html(
        related='job_id.kanban_notes',
        string="Job Position Notes",
        readonly=False,
        store=False
    )

    interview_invite_ids = fields.One2many(
        'recruitment.interview.invite',
        'applicant_id',
        string="Interview Invites"
    )

    next_interview_date = fields.Datetime(
        string="Next Interview",
        compute="_compute_next_interview_date",
        store=True,
        help="Date of the next scheduled interview"
    )

    @api.depends('interview_invite_ids.start_datetime', 'interview_invite_ids.status')
    def _compute_next_interview_date(self):
        for applicant in self:
            upcoming_interviews = self.env['recruitment.interview.invite'].search([
                ('applicant_id', '=', applicant.id),
                ('start_datetime', '>=', fields.Datetime.now()),
                ('status', 'not in', ['cancelled', 'rejected'])
            ], order='start_datetime asc', limit=1)

            applicant.next_interview_date = upcoming_interviews.start_datetime if upcoming_interviews else False

    @api.depends('stage_id', 'stage_id.name')
    def _compute_show_interview_button(self):
        for record in self:
            if record.stage_id and record.stage_id.name:
                record.show_interview_button = 'interview' in record.stage_id.name.lower()
            else:
                record.show_interview_button = False

    def action_show_job_notes(self):
        """Open job position notes in a dialog (same simple form as Job kanban)."""
        self.ensure_one()
        return {
            'name': 'Job Notes',
            'type': 'ir.actions.act_window',
            'res_model': 'hr.job',
            'res_id': self.job_id.id,
            'view_mode': 'form',
            'view_id': self.env.ref('recruitment_interview_manager.hr_job_view_form_simple_notes').id,
            'target': 'new',
        }

    def action_open_interview_invite(self):
        self.ensure_one()

        partner = self.partner_id
        if not partner and self.email_from:
            partner = self.env['res.partner'].search([('email', '=', self.email_from)], limit=1)

        if not partner:
            partner_vals = {
                'name': self.partner_name or self.name,
                'email': self.email_from,
                'phone': self.partner_phone,
                'mobile': self.partner_mobile,
                'is_company': False,
            }
            partner = self.env['res.partner'].create(partner_vals)
            self.write({'partner_id': partner.id})

        default_context = {
            'default_candidate_id': partner.id,
            'default_applicant_id': self.id,
            'default_position_text': self.job_id.name if self.job_id else '',
        }

        return {
            'name': 'Schedule Interview',
            'type': 'ir.actions.act_window',
            'res_model': 'recruitment.interview.invite',
            'view_mode': 'form',
            'target': 'new',
            'context': default_context,
        }

