    mail_sender = client.mail_sender
    send_mail_endpoint = self.SEND_MAIL_ENDPOINT.format(user_id=mail_sender)

    if teams_link:
        candidate_email_content = candidate_body_html.replace(
            "TEAMS Link", 
            f"<a href='{teams_link}'>Join Microsoft Teams Meeting</a>"
        )
    else:
        candidate_email_content = candidate_body_html

