            attachments_list.append({
                '@odata.type': '#microsoft.graph.fileAttachment',
                'name': file_name,
                'contentType': 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                'contentBytes': file_content_b64
            })
            self.message_post(body=self.env._("Prepared attachment: %(name)s") % {"name": file_name}, subtype_xmlid="mail.mt_note")
        except UserError as e:
            self.message_post(body=self.env._("WARNING: SOW/RFI file preparation failed. Error: %(error)s") % {"error": e}, subtype_xmlid="mail.mt_note")

    if self.include_excel_test:
        try:
            file_name, file_content_b64 = self._read_local_file_data(self.FILE_EXCEL_TEST)
            attachments_list.append({
                '@odata.type': '#microsoft.graph.fileAttachment',
                'name': file_name,
                'contentType': 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
                'contentBytes': file_content_b64
            })
            self.message_post(body=self.env._("Prepared attachment: %(name)s") % {"name": file_name}, subtype_xmlid="mail.mt_note")

