.o_notebook .o_field_widget.o_field_one2many .o_list_table th,
.o_notebook .o_field_widget.o_field_many2many .o_list_table td,
.o_notebook .o_field_widget.o_field_many2many .o_list_table th {
    padding: 4px 6px !important;
}

/* ========================================================================
   Buttons in List Views (Inside Notebooks Only)
   ======================================================================== */

/* Make action buttons more compact */
.o_notebook .o_list_table .o_list_button {
    padding: 3px 8px !important;
    font-size: 14px;
}

/* ========================================================================
   Status Badges (Inside Notebooks Only)
   ======================================================================== */

/* Compact badges/tags in list views */
.o_notebook .o_list_table .badge {
    padding: 3px 8px;
    font-size: 13px;
}

/* ========================================================================
   Checkbox and Selection Fields (Inside Notebooks Only)
   ======================================================================== */

/* Center checkboxes with reduced padding */
.o_notebook .o_list_table .o_list_record_selector {
    padding: 0 !important;
    text-align: center;
}

/* ========================================================================
   HTML Fields - Full Content Display
   ======================================================================== */

/* Force HTML widget to show full content with minimum height */
.o_list_table .o_field_html iframe,
.o_list_table .o_field_html .note-editor,
.o_list_table .o_field_html .o_readonly {
    min-height: 60px !important;
    max-height: none !important;
    height: auto !important;
}

